from flask import Flask, request, jsonify, g
import logging
import json
import time
from functools import wraps
import os

# Configure logging
logging.basicConfig(
    level=logging.INFO,
    format='%(asctime)s - %(name)s - %(levelname)s - %(message)s',
    handlers=[
        logging.FileHandler('app.log'),
        logging.StreamHandler()
    ]
)

logger = logging.getLogger(__name__)

app = Flask(__name__)

# Middleware to log all requests
@app.before_request
def log_request_info():
    g.start_time = time.time()
    logger.info(f"Request: {request.method} {request.url}")
    logger.info(f"Headers: {dict(request.headers)}")
    
    if request.is_json:
        logger.info(f"Body: {request.get_json()}")
    elif request.data:
        logger.info(f"Body: {request.data.decode('utf-8')}")

# Middleware to log all responses
@app.after_request
def log_response_info(response):
    duration = time.time() - g.start_time
    logger.info(f"Response: {response.status_code} - Duration: {duration:.2f}s")
    logger.info(f"Response Body: {response.get_data(as_text=True)}")
    return response

# Error handler
@app.errorhandler(Exception)
def handle_exception(e):
    logger.error(f"Unhandled exception: {str(e)}", exc_info=True)
    return jsonify({"error": "Internal server error"}), 500

# Authentication decorator
def require_auth(f):
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth = request.headers.get('Authorization')
        if not auth:
            logger.warning("Authentication failed: No authorization header")
            return jsonify({"error": "Authentication required"}), 401
        
        # Log authentication attempt for debugging
        logger.info(f"Authentication attempt: {auth}")
        
        # Simple token validation (replace with your logic)
        if auth != "Bearer valid_token":
            logger.warning("Authentication failed: Invalid token")
            return jsonify({"error": "Invalid token"}), 401
            
        return f(*args, **kwargs)
    return decorated_function

